def base_discount(price, tier):
    if tier == "gold":
        return price * 0.20
    if tier == "silver":
        return price * 0.10
    if tier == "bronze":
        return price * 0.05
    return 0.0


def seasonal_bonus(price, is_holiday):
    if is_holiday:
        return price * 0.05
    return 0.0


def loyalty_bonus(years):
    if years >= 5:
        return 0.03
    if years >= 2:
        return 0.01
    return 0.0


def total_discount(price, tier, is_holiday, years):
    discount = base_discount(price, tier)
    discount += seasonal_bonus(price, is_holiday)
    discount += price * loyalty_bonus(years)
    return min(discount, price * 0.5)


def final_price(price, tier, is_holiday, years):
    return round(price - total_discount(price, tier, is_holiday, years), 2)
